  6	
  7	afterEach(cleanup);
  8	
  9	describe('manage fields', () => {
 10	  it('gets initialized from the defaults', () => {
 11	    const {
 12	      result: {
 13	        current: [fields],
 14	      },
 15	    } = renderHook(() => useFields(undefined, [{ label: '', resourceFieldId: NAME }]));
 16	    expect(fields).toMatchObject([{ isVisible: false, resourceFieldId: NAME }]);
 17	  });
 18	  it('enables namespace column visibility if no namespace is chosen', () => {
 19	    const {
 20	      result: {
 21	        current: [fields],
 22	      },
 23	    } = renderHook(() =>
 24	      useFields(undefined, [
 25	        { isVisible: true, label: '', resourceFieldId: NAME },
 26	        { isVisible: false, label: '', resourceFieldId: NAMESPACE },
 27	      ]),
 28	    );
 29	    expect(fields).toMatchObject([
 30	      { isVisible: true, resourceFieldId: NAME },
 31	      { isVisible: true, resourceFieldId: NAMESPACE },
 32	    ]);
 33	  });
 34	  it('disables namespace column visibility if a namespace is chosen', () => {
 35	    const {
 36	      result: {
 37	        current: [fields],
 38	      },
 39	    } = renderHook(() =>
 40	      useFields('some_namespace', [
 41	        { isVisible: true, label: '', resourceFieldId: NAME },
 42	        { isVisible: true, label: '', resourceFieldId: NAMESPACE },
 43	      ]),
 44	    );
 45	    expect(fields).toMatchObject([
 46	      { isVisible: true, resourceFieldId: NAME },
 47	      { isVisible: false, resourceFieldId: NAMESPACE },
 48	    ]);
 49	  });
 50	});
 51	
 52	describe('initialize fields from user settings', () => {
 53	  it('uses a reverse order', () => {
 54	    const {
 55	      result: {
 56	        current: [fields],
 57	      },
 58	    } = renderHook(() =>
 59	      useFields(
 60	        undefined,
 61	        [
 62	          { isVisible: true, label: '', resourceFieldId: NAME },
 63	          { isVisible: true, label: '', resourceFieldId: NAMESPACE },
 64	        ],
 65	        {
 66	          clear: () => undefined,
 67	          data: [
 68	            { isVisible: true, resourceFieldId: NAMESPACE },
 69	            { isVisible: true, resourceFieldId: NAME },
 70	          ],
 71	          save: () => undefined,
 72	        },
 73	      ),
 74	    );
 75	    expect(fields).toMatchObject([
 76	      { isVisible: true, resourceFieldId: NAMESPACE },
 77	      { isVisible: true, resourceFieldId: NAME },
 78	    ]);
 79	  });
 80	
 81	  it('tries to hide identity column', () => {
 82	    const {
 83	      result: {
 84	        current: [fields],
 85	      },
 86	    } = renderHook(() =>
 87	      useFields(
 88	        'some-namespace',
 89	        [
 90	          { isIdentity: true, isVisible: true, label: '', resourceFieldId: NAME },
 91	          { isVisible: true, label: '', resourceFieldId: NAMESPACE },
 92	        ],
 93	        {
 94	          clear: () => undefined,
 95	          data: [
 96	            { isVisible: false, resourceFieldId: NAME },
 97	            { isVisible: false, resourceFieldId: NAMESPACE },
 98	          ],
 99	          save: () => undefined,
100	        },
101	      ),
102	    );
103	    expect(fields).toMatchObject([
104	      { isVisible: true, resourceFieldId: NAME },
105	      { isVisible: false, resourceFieldId: NAMESPACE },
106	    ]);
107	  });
108	  it('filters out duplicated and unsupported fields', () => {
109	    const {
110	      result: {
111	        current: [fields],
112	      },
113	    } = renderHook(() =>
114	      useFields(
115	        undefined,
116	        [
117	          { isVisible: true, label: '', resourceFieldId: NAME },
118	          { isVisible: true, label: '', resourceFieldId: NAMESPACE },
119	        ],
120	        {
121	          clear: () => undefined,
122	          data: [
123	            { isVisible: false, resourceFieldId: NAME },
124	            { isVisible: true, resourceFieldId: NAME },
125	            { isVisible: false, resourceFieldId: 'foo' },
126	          ],
127	          save: () => undefined,
128	        },
129	      ),
130	    );
131	    expect(fields).toMatchObject([
132	      { isVisible: false, resourceFieldId: NAME },
133	      { isVisible: true, resourceFieldId: NAMESPACE },
134	    ]);
135	  });
136	});
