138	describe('saves fields to user settings', () => {
139	  it('saves re-order and hidden NAME field)', () => {
140	    const saveSettings = jest.fn();
141	    const {
142	      result: {
143	        current: [, setFields],
144	      },
145	    } = renderHook(() =>
146	      useFields(
147	        undefined,
148	        [
149	          { isVisible: true, label: '', resourceFieldId: NAME },
150	          { isVisible: true, label: '', resourceFieldId: NAMESPACE },
151	        ],
152	        { clear: () => undefined, data: [], save: saveSettings },
153	      ),
154	    );
155	    act(() => {
156	      setFields([
157	        { isVisible: true, label: '', resourceFieldId: NAMESPACE },
158	        { isVisible: false, label: '', resourceFieldId: NAME },
159	      ]);
160	    });
161	    expect(saveSettings).toBeCalledWith([
162	      { isVisible: true, resourceFieldId: NAMESPACE },
163	      { isVisible: false, resourceFieldId: NAME },
164	    ]);
165	  });
166	  it('clears settings if equal to defaults)', () => {
167	    const clearSettings = jest.fn();
168	    const {
169	      result: {
170	        current: [, setFields],
171	      },
172	    } = renderHook(() =>
173	      useFields(
174	        undefined,
175	        [
176	          { isVisible: true, label: '', resourceFieldId: NAME },
177	          { isVisible: true, label: '', resourceFieldId: NAMESPACE },
178	        ],
179	        { clear: clearSettings, data: [], save: () => undefined },
180	      ),
181	    );
182	    act(() => {
183	      setFields([
184	        { isVisible: true, label: '', resourceFieldId: NAME },
185	        { isVisible: true, label: '', resourceFieldId: NAMESPACE },
186	      ]);
187	    });
188	    expect(clearSettings).toBeCalled();
189	  });
190	});

